class Solution:
    def minCuttingCost(self, n, m, k):
        cost = 0
        for x in (n, m):
            if x > k:
                best = None
                for a in range(1, x):
                    b = x - a
                    if a <= k and b <= k:
                        c = a * b
                        if best is None or c < best:
                            best = c
                cost += best
        return cost

